1	type Item = {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	};
7	type Customer = { yearsWithMHPCO: number };
8	type QuoteStep = { op: "quote"; items: Item[] };
9	type Damage = { itemType: string; amount: number };
10	type ClaimStep = {
11	  op: "claim";
12	  policy: number;
13	  incident: { cause: string; damages: Damage[] };
14	};
15	type Step = QuoteStep | ClaimStep;
16	type Scenario = {
17	  customer: Customer;
18	  steps: Step[];
19	};
20	
21	const PROCESSING_FEE = 5;
22	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
23	const CURSE_SURCHARGE_RATE = 0.5;
24	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
25	const HIGH_ENCHANTMENT_THRESHOLD = 5;
26	const LOYALTY_DISCOUNT_RATE = 0.2;
27	const LOYALTY_THRESHOLD_YEARS = 2;
28	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
29	const ITEM_BASE: Record<string, number> = {
30	  sword: 100,
31	  amulet: 60,
32	  staff: 80,
33	  potion: 40,
34	  rune: 25,
35	  moonstone: 25,
36	};
37	const ITEM_INSURANCE_VALUE: Record<string, number> = {
38	  sword: 1000,
39	  amulet: 600,
40	  staff: 800,
41	  potion: 400,
42	  rune: 250,
43	  moonstone: 250,
44	};
45	const DEDUCTIBLE = 100;
46	const CAP_MULTIPLIER = 2;
47	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
48	const HIGH_ENCHANTMENT_DAMAGE_THRESHOLD = 8;
49	
50	const COMPONENT_BLOCK_SIZE = 3;
51	const COMPONENT_BLOCK_BASE = 60;
52	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
53	
54	const countByKey = <T>(values: T[], keyOf: (value: T) => string): Map<string, number> => {
55	  const counts = new Map<string, number>();
56	  for (const value of values) {
57	    const key = keyOf(value);
58	    counts.set(key, (counts.get(key) ?? 0) + 1);
59	  }
60	  return counts;
61	};
62	
63	const groupCountsByType = (items: Item[]): Map<string, number> =>
64	  countByKey(items, (item) => item.type);
65	
66	const baseForGroup = (type: string, count: number): number => {
67	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
68	    return COMPONENT_BLOCK_BASE;
69	  }
70	  return count * ITEM_BASE[type];
71	};
72	
73	const calculatePolicyBase = (items: Item[]): number => {
74	  let total = 0;
75	  for (const [type, count] of groupCountsByType(items)) {
76	    total += baseForGroup(type, count);
77	  }
78	  return total;
79	};
80	
81	const roundUpInMHPCOsFavor = (amount: number): number => Math.ceil(amount);
82	
83	type Modifier<T> = { applies: (target: T) => boolean; rate: number };
84	
85	const sumApplicableRates = <T>(modifiers: Modifier<T>[], target: T, base: number): number =>
86	  modifiers.reduce(
87	    (sum, { applies, rate }) => sum + (applies(target) ? base * rate : 0),
88	    0,
89	  );
90	
91	const ITEM_SURCHARGES: Modifier<Item>[] = [
92	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE_RATE },
93	  {
94	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
95	    rate: HIGH_ENCHANTMENT_SURCHARGE_RATE,
96	  },
97	];
98	
99	const surchargesForItem = (item: Item): number =>
100	  sumApplicableRates(ITEM_SURCHARGES, item, ITEM_BASE[item.type]);
101	
102	const itemSpecificSurcharges = (items: Item[]): number =>
103	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
104	
105	type PolicyContext = { customer: Customer; quoteIndex: number };
106	
107	const POLICY_MODIFIERS: Modifier<PolicyContext>[] = [
108	  { applies: () => true, rate: +FIRST_CONTRACT_SURCHARGE_RATE },
109	  {
110	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
111	    rate: -LOYALTY_DISCOUNT_RATE,
112	  },
113	  {
114	    applies: ({ quoteIndex }) => quoteIndex > 0,
115	    rate: -FOLLOW_UP_DISCOUNT_RATE,
116	  },
117	];
118	
119	const policyWideAdjustment = (policyBase: number, context: PolicyContext): number =>
120	  sumApplicableRates(POLICY_MODIFIERS, context, policyBase);
121	
122	const quotePremium = (items: Item[], context: PolicyContext): number => {
